  1→import { useState, useEffect } from "react";
  2→import {
  3→  GitBranch,
  4→  BookOpen,
  5→  Plus,
  6→  ChevronRight,
  7→  ChevronDown,
  8→  FolderGit2,
  9→  Loader2,
 10→} from "lucide-react";
 11→import type { Tab } from "../../App";
 12→import type { BranchInfo, RepoInfo, WorktreeInfo } from "../../lib/ipc";
 13→import { useReposQuery } from "../../hooks/use-tauri-query";
 14→
 15→interface SidebarProps {
 16→  activeTab: Tab;
 17→  onBranchSelect: (branch: BranchInfo, repoPath: string) => void;
 18→  onWorktreeSelect: (wt: WorktreeInfo, repoPath: string) => void;
 19→  onNewSession?: () => void;
 20→}
 21→
 22→// Fallback mock data when no real repos are discovered
 23→const MOCK_REPOS: RepoInfo[] = [
 24→  {
 25→    path: "/Users/alisha/Projects/myapp",
 26→    name: "myapp",
 27→    branches: [
 28→      { name: "main", is_head: true, checkpoint_count: 12 },
 29→      { name: "feat-auth", is_head: false, checkpoint_count: 5 },
 30→      { name: "fix-null-check", is_head: false, checkpoint_count: 3 },
 31→    ],
 32→    worktrees: [
 33→      { path: "/Users/alisha/Projects/wt/feat-auth", branch: "feat-auth", is_main: false },
 34→      { path: "/Users/alisha/Projects/wt/fix-null-check", branch: "fix-null-check", is_main: false },
 35→    ],
 36→  },
 37→];
 38→
 39→const MOCK_TRAILS = [
 40→  { id: "#12", title: "Add JWT auth", status: "open" as const },
 41→  { id: "#15", title: "Fix null deref", status: "review" as const },
 42→  { id: "#18", title: "Refactor DB pool", status: "draft" as const },
 43→];
 44→
 45→export function Sidebar({
 46→  activeTab,
 47→  onBranchSelect,
 48→  onWorktreeSelect,
 49→  onNewSession,
 50→}: SidebarProps) {
 51→  const { data: realRepos, isLoading, error } = useReposQuery();
 52→
 53→  // Use real repos if available, otherwise mock
 54→  const repos = realRepos && realRepos.length > 0 ? realRepos : MOCK_REPOS;
 55→  const isUsingMock = !realRepos || realRepos.length === 0;
 56→
 57→  const [expandedRepos, setExpandedRepos] = useState<Set<string>>(new Set());
 58→
 59→  // Auto-expand all repos when data loads
 60→  useEffect(() => {
 61→    setExpandedRepos(new Set(repos.map((r) => r.path)));
 62→  }, [repos]);
 63→
 64→  function toggleRepo(path: string) {
 65→    setExpandedRepos((prev) => {
 66→      const next = new Set(prev);
 67→      if (next.has(path)) next.delete(path);
 68→      else next.add(path);
 69→      return next;
 70→    });
 71→  }
 72→
 73→  const worktreeBranches = new Set(
 74→    repos.flatMap((r) => r.worktrees.map((wt) => wt.branch))
 75→  );
 76→
 77→  return (
 78→    <div className="flex w-[240px] shrink-0 flex-col border-r border-border bg-bg-raised">
 79→      {/* Header */}
 80→      <div className="border-b border-border-subtle p-4">
 81→        <h2 className="flex items-center gap-2 text-[15px] font-semibold text-fg">
 82→          <FolderGit2 size={18} />
 83→          Repositories
 84→        </h2>
 85→      </div>
 86→
 87→      {/* Repo list */}
 88→      <div className="flex-1 overflow-y-auto py-3">
 89→        <div className="mb-1 flex items-center gap-2 px-4">
 90→          <span className="text-[10px] font-semibold uppercase tracking-wider text-fg-subtle">
 91→            {isUsingMock ? "Demo" : "Active"}
 92→          </span>
 93→          {isLoading && <Loader2 size={10} className="animate-spin text-fg-subtle" />}
 94→        </div>
 95→
 96→        {error && (
 97→          <div className="px-4 py-2 text-[11px] text-red">
 98→            Failed to load repos
 99→          </div>
100→        )}
101→
102→        {repos.map((repo) => (
103→          <div key={repo.path}>
104→            <button
105→              onClick={() => toggleRepo(repo.path)}
106→              className="flex w-full items-center gap-2.5 px-4 py-[7px] text-[13px] text-fg-muted transition-colors hover:bg-bg-hover hover:text-fg"
107→            >
108→              {expandedRepos.has(repo.path) ? (
109→                <ChevronDown size={14} />
110→              ) : (
111→                <ChevronRight size={14} />
112→              )}
113→              <BookOpen size={14} />
114→              {repo.name}
115→              <span className="ml-auto rounded-lg bg-bg-hover px-1.5 text-[10px] text-fg-subtle">
116→                {repo.branches.length}
117→              </span>
118→            </button>
119→
120→            {expandedRepos.has(repo.path) && (
121→              <div className="pl-8">
122→                {repo.branches.map((branch) => {
123→                  const isWorktree = worktreeBranches.has(branch.name);
124→                  const isActive =
125→                    activeTab.branch === branch.name &&
126→                    activeTab.repoPath === repo.path;
127→
128→                  return (
129→                    <button
130→                      key={branch.name}
131→                      onClick={() => {
132→                        const wt = repo.worktrees.find(
133→                          (w) => w.branch === branch.name
134→                        );
135→                        if (wt) {
136→                          onWorktreeSelect(wt, repo.path);
137→                        } else {
138→                          onBranchSelect(branch, repo.path);
139→                        }
140→                      }}
141→                      className={`flex w-full items-center gap-2 px-2 py-[7px] text-[13px] transition-colors ${
142→                        isActive
143→                          ? "bg-accent-bg text-accent-fg"
144→                          : "text-fg-muted hover:bg-bg-hover hover:text-fg"
145→                      }`}
146→                    >
147→                      <GitBranch size={12} />
148→                      {branch.name}
149→                      {isWorktree && (
150→                        <span className="ml-auto rounded bg-green-bg px-1.5 py-0.5 text-[9px] font-medium text-green">
151→                          worktree
152→                        </span>
153→                      )}
154→                      {!isWorktree && (
155→                        <span className="ml-auto rounded-lg bg-bg-hover px-1.5 text-[10px] text-fg-subtle">
156→                          {branch.checkpoint_count}
157→                        </span>
158→                      )}
159→                    </button>
160→                  );
161→                })}
162→              </div>
163→            )}
164→          </div>
165→        ))}
166→
167→        {/* Trails section */}
168→        <div className="mx-4 my-1 h-px bg-border-subtle" />
169→        <div className="mb-1 mt-3 px-4 text-[10px] font-semibold uppercase tracking-wider text-fg-subtle">
170→          Trails
171→        </div>
172→        {MOCK_TRAILS.map((trail) => (
173→          <button
174→            key={trail.id}
175→            className="flex w-full items-center gap-2.5 px-4 py-[7px] text-[13px] text-fg-muted transition-colors hover:bg-bg-hover hover:text-fg"
176→          >
177→            <span
178→              className={`h-2 w-2 rounded-full ${
179→                trail.status === "open"
180→                  ? "bg-green"
181→                  : trail.status === "review"
182→                    ? "bg-yellow"
183→                    : "bg-fg-subtle"
184→              }`}
185→            />
186→            {trail.id} {trail.title}
187→          </button>
188→        ))}
189→      </div>
190→
191→      {/* New session button */}
192→      <div className="border-t border-border-subtle p-3">
193→        <button
194→          onClick={onNewSession}
195→          className="flex w-full items-center justify-center gap-1.5 rounded-lg bg-accent px-3 py-2 text-xs font-medium text-white transition-colors hover:bg-accent-hover"
196→        >
197→          <Plus size={14} />
198→          New Session
199→        </button>
200→      </div>
201→    </div>
202→  );
203→}
