100→function timeAgo(isoDate: string): string {
101→  const diff = Date.now() - new Date(isoDate).getTime();
102→  const mins = Math.floor(diff / 60000);
103→  if (mins < 1) return "just now";
104→  if (mins < 60) return `${mins}m ago`;
105→  const hours = Math.floor(mins / 60);
106→  if (hours < 24) return `${hours}h ago`;
107→  return `${Math.floor(hours / 24)}d ago`;
108→}
