110→export function TrailList({ repoPath, onSelectTrail }: TrailListProps) {
111→  const { data: realTrails, isLoading } = useTrailsQuery(repoPath);
112→  const trails = realTrails && realTrails.length > 0 ? realTrails : MOCK_TRAILS;
113→
114→  const [selectedId, setSelectedId] = useState<string | null>(null);
115→  const [statusFilter, setStatusFilter] = useState<string | null>(null);
116→
117→  const filtered = statusFilter
118→    ? trails.filter((t) => t.metadata.status === statusFilter)
119→    : trails;
120→
121→  const statuses = [...new Set(trails.map((t) => t.metadata.status))];
122→
123→  return (
124→    <div>
125→      {/* Filter chips */}
126→      <div className="flex gap-1.5 px-5 pt-4 pb-2 overflow-x-auto">
127→        <button
128→          onClick={() => setStatusFilter(null)}
129→          className={`shrink-0 rounded-full px-3 py-1 text-[11px] font-medium transition-colors ${
130→            !statusFilter
131→              ? "bg-accent text-white"
132→              : "bg-bg-overlay text-fg-muted hover:bg-bg-hover"
133→          }`}
134→        >
135→          All ({trails.length})
136→        </button>
137→        {statuses.map((status) => {
138→          const colors = STATUS_COLORS[status] ?? STATUS_COLORS.draft;
139→          const count = trails.filter((t) => t.metadata.status === status).length;
140→          return (
141→            <button
142→              key={status}
143→              onClick={() => setStatusFilter(statusFilter === status ? null : status)}
144→              className={`flex shrink-0 items-center gap-1.5 rounded-full px-3 py-1 text-[11px] font-medium transition-colors ${
145→                statusFilter === status
146→                  ? `${colors.bg} ${colors.text}`
147→                  : "bg-bg-overlay text-fg-muted hover:bg-bg-hover"
148→              }`}
149→            >
150→              <span className={`h-1.5 w-1.5 rounded-full ${colors.dot}`} />
151→              {status.replace("_", " ")} ({count})
152→            </button>
153→          );
154→        })}
155→        {isLoading && <Loader2 size={14} className="animate-spin text-fg-subtle ml-2 self-center" />}
156→      </div>
157→
158→      {/* Trail list */}
159→      <div className="px-5 pb-5 pt-2">
160→        {filtered.map((trail) => {
161→          const m = trail.metadata;
162→          const colors = STATUS_COLORS[m.status] ?? STATUS_COLORS.draft;
163→          const priority = PRIORITY_LABELS[m.priority];
164→
165→          return (
166→            <button
167→              key={m.trail_id}
168→              onClick={() => {
169→                setSelectedId(m.trail_id);
170→                onSelectTrail?.(trail);
171→              }}
172→              className={`mb-2 flex w-full gap-3 rounded-[10px] border p-4 text-left transition-all ${
173→                selectedId === m.trail_id
174→                  ? "border-accent bg-accent-bg"
175→                  : "border-border-subtle bg-bg-overlay hover:border-border-hover hover:bg-bg-hover"
176→              }`}
177→            >
178→              {/* Status icon */}
179→              <div className={`flex h-8 w-8 shrink-0 items-center justify-center rounded-full ${colors.bg}`}>
180→                <GitPullRequest size={16} className={colors.text} />
181→              </div>
182→
183→              {/* Content */}
184→              <div className="min-w-0 flex-1">
185→                <div className="mb-1 flex items-center gap-2">
186→                  <span className="text-[13px] font-medium text-fg">
187→                    {m.title}
188→                  </span>
189→                  <span className={`shrink-0 rounded-full px-2 py-0.5 text-[10px] font-medium ${colors.bg} ${colors.text}`}>
190→                    {m.status.replace("_", " ")}
191→                  </span>
192→                  {priority && (
193→                    <span className={`text-[10px] font-medium ${priority.color}`}>
194→                      {priority.label}
195→                    </span>
196→                  )}
197→                </div>
198→
199→                <div className="mb-2 text-xs text-fg-muted">
200→                  <span className="font-mono text-fg-subtle">{m.branch}</span>
201→                  <span className="mx-1.5">→</span>
202→                  <span className="font-mono text-fg-subtle">{m.base}</span>
203→                </div>
204→
205→                <div className="flex gap-4 text-[11px] text-fg-subtle">
206→                  <span className="flex items-center gap-1">
207→                    <GitCommit size={11} />
208→                    {trail.checkpoint_count} checkpoints
209→                  </span>
210→                  <span className="flex items-center gap-1">
211→                    <MessageSquare size={11} />
212→                    {trail.comment_count} comments
213→                  </span>
214→                  {m.labels.map((label) => (
215→                    <span
216→                      key={label}
217→                      className="rounded bg-bg-hover px-1.5 py-0.5 text-[10px]"
218→                    >
219→                      {label}
220→                    </span>
221→                  ))}
222→                </div>
223→              </div>
224→
225→              {/* Right side */}
226→              <div className="flex shrink-0 flex-col items-end gap-1">
227→                <span className="text-[11px] text-fg-subtle">
228→                  {timeAgo(m.updated_at)}
229→                </span>
230→                {m.reviewers.length > 0 && (
231→                  <div className="flex gap-1">
232→                    {m.reviewers.map((r) => (
233→                      <span
234→                        key={r.login}
235→                        className={`rounded-full px-1.5 py-0.5 text-[9px] font-medium ${
236→                          r.status === "approved"
237→                            ? "bg-green-bg text-green"
238→                            : r.status === "changes_requested"
239→                              ? "bg-yellow-bg text-yellow"
240→                              : "bg-bg-hover text-fg-subtle"
241→                        }`}
242→                      >
243→                        {r.login}
244→                      </span>
245→                    ))}
246→                  </div>
247→                )}
248→                <ChevronRight size={14} className="text-fg-faint" />
249→              </div>
250→            </button>
251→          );
252→        })}
253→
254→        {filtered.length === 0 && !isLoading && (
255→          <div className="py-12 text-center text-sm text-fg-subtle">
256→            No trails found
257→          </div>
258→        )}
259→      </div>
260→    </div>
261→  );
262→}
