 56→function formatTokens(usage: CheckpointSummary["token_usage"]): string | null {
 57→  if (!usage) return null;
 58→  const total = usage.input_tokens + usage.output_tokens;
 59→  if (total >= 1000) return `${(total / 1000).toFixed(1)}k tokens`;
 60→  return `${total} tokens`;
 61→}
