 65→  const mins = Math.floor(diff / 60000);
 66→  if (mins < 1) return "just now";
 67→  if (mins < 60) return `${mins}m ago`;
 68→  const hours = Math.floor(mins / 60);
 69→  if (hours < 24) return `${hours}h ago`;
 70→  return `${Math.floor(hours / 24)}d ago`;
 71→}
