 78→    ? realCheckpoints
 79→    : MOCK_CHECKPOINTS;
 80→
 81→  const [selectedId, setSelectedId] = useState<string | null>(null);
 82→  const [search, setSearch] = useState("");
 83→
 84→  const filtered = search
 85→    ? checkpoints.filter((cp) =>
 86→        cp.commit_message.toLowerCase().includes(search.toLowerCase()) ||
 87→        cp.checkpoint_id.toLowerCase().includes(search.toLowerCase())
 88→      )
 89→    : checkpoints;
 90→
 91→  return (
 92→    <div>
 93→      {/* Search */}
 94→      <div className="p-5 pb-3">
 95→        <div className="relative">
 96→          <Search
 97→            size={14}
 98→            className="absolute left-3 top-1/2 -translate-y-1/2 text-fg-subtle"
 99→          />
100→          <input
101→            value={search}
102→            onChange={(e) => setSearch(e.target.value)}
103→            placeholder="Search checkpoints... (⌘K)"
104→            className="w-full rounded-lg border border-border bg-bg-overlay py-2 pl-9 pr-3 text-[13px] text-fg outline-none transition-colors placeholder:text-fg-subtle focus:border-accent"
