112→        </div>
113→      </div>
114→
115→      {/* List */}
116→      <div className="px-5 pb-5">
117→        {filtered.map((cp) => {
118→          const agent = cp.sessions[0]?.agent ?? null;
119→          const stepCount = cp.sessions.reduce((sum, s) => sum + s.step_count, 0);
120→          const tokens = formatTokens(cp.token_usage);
121→          const isManual = cp.sessions.length === 0;
122→
123→          return (
124→            <button
125→              key={cp.checkpoint_id}
