132→                  ? "border-accent bg-accent-bg"
133→                  : "border-border-subtle bg-bg-overlay hover:border-border-hover hover:bg-bg-hover"
134→              }`}
135→            >
136→              {/* Avatar */}
137→              <div className="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-bg-hover text-sm">
138→                {agent ? "🤖" : "👤"}
139→              </div>
140→
141→              {/* Content */}
142→              <div className="min-w-0 flex-1">
143→                <div className="mb-1 flex items-center gap-2">
144→                  <span className="truncate text-[13px] font-medium text-fg">
145→                    {cp.commit_message || cp.checkpoint_id}
146→                  </span>
147→                  {agent && (
148→                    <span
149→                      className={`shrink-0 rounded px-2 py-0.5 text-[10px] font-medium ${
150→                        agent === "Claude Code"
151→                          ? "bg-accent-bg text-accent-fg"
152→                          : "bg-green-bg text-green"
153→                      }`}
154→                    >
155→                      {agent}
156→                    </span>
157→                  )}
158→                </div>
159→                <div className="flex gap-3 text-[11px] text-fg-muted">
160→                  <span className="font-mono text-fg-subtle">
161→                    {cp.commit_sha ? cp.commit_sha.slice(0, 7) : cp.checkpoint_id.slice(0, 7)}
162→                  </span>
163→                  <span>{cp.files_touched.length} files</span>
164→                  {stepCount > 0 && <span>{stepCount} steps</span>}
165→                  {tokens && <span>{tokens}</span>}
166→                  {isManual && (
167→                    <span className="text-fg-subtle">manual commit</span>
168→                  )}
169→                </div>
170→              </div>
171→
172→              {/* Time */}
173→              {cp.created_at && (
174→                <span className="shrink-0 self-start text-[11px] text-fg-subtle whitespace-nowrap">
175→                  {timeAgo(cp.created_at)}
176→                </span>
177→              )}
178→            </button>
179→          );
180→        })}
181→
182→        {filtered.length === 0 && !isLoading && (
183→          <div className="py-12 text-center text-sm text-fg-subtle">
184→            No checkpoints found
185→          </div>
186→        )}
187→      </div>
188→    </div>
189→  );
190→}
