  1→import { useState, useEffect } from "react";
  2→import { Sidebar } from "./features/repos/Sidebar";
  3→import { TitleBar } from "./components/TitleBar";
  4→import { TabBar } from "./components/TabBar";
  5→import { CheckpointList } from "./features/checkpoints/CheckpointList";
  6→import { TranscriptView } from "./features/transcripts/TranscriptView";
  7→import { TrailList } from "./features/trails/TrailList";
  8→import { TerminalPanel } from "./features/terminal/TerminalPanel";
  9→import { useLiveUpdates } from "./hooks/use-live-updates";
 10→import type { BranchInfo, CheckpointSummary, WorktreeInfo } from "./lib/ipc";
 11→
 12→export interface Tab {
 13→  id: string;
 14→  branch: string;
 15→  repoPath: string;
 16→  worktree: WorktreeInfo | null;
 17→  hasActiveSession: boolean;
 18→}
 19→
 20→export default function App() {
 21→  const [tabs, setTabs] = useState<Tab[]>([
 22→    {
 23→      id: "main",
 24→      branch: "main",
 25→      repoPath: "",
 26→      worktree: null,
 27→      hasActiveSession: false,
 28→    },
 29→  ]);
 30→  const [activeTabId, setActiveTabId] = useState("main");
 31→  const [terminalHeight, setTerminalHeight] = useState(
 32→    () => Number(localStorage.getItem("entire:terminal-height")) || 220
 33→  );
 34→  const [isTerminalOpen, setIsTerminalOpen] = useState(
 35→    () => localStorage.getItem("entire:terminal-open") !== "false"
 36→  );
 37→  const [innerTab, setInnerTab] = useState<
 38→    "checkpoints" | "transcript" | "trails" | "diff"
 39→  >("checkpoints");
 40→  const [selectedCheckpoint, setSelectedCheckpoint] =
 41→    useState<CheckpointSummary | null>(null);
 42→
 43→  const activeTab = tabs.find((t) => t.id === activeTabId) ?? tabs[0];
 44→
 45→  // Live updates — watch active repo for checkpoint/session changes
 46→  useLiveUpdates(activeTab.repoPath);
 47→
 48→  // Persist UI state to localStorage
 49→  useEffect(() => {
 50→    localStorage.setItem("entire:terminal-height", String(terminalHeight));
 51→  }, [terminalHeight]);
 52→  useEffect(() => {
 53→    localStorage.setItem("entire:terminal-open", String(isTerminalOpen));
 54→  }, [isTerminalOpen]);
 55→
 56→  // Keyboard shortcuts
 57→  useEffect(() => {
 58→    function onKeyDown(e: KeyboardEvent) {
 59→      const meta = e.metaKey || e.ctrlKey;
 60→
 61→      // Cmd+K = focus search
 62→      if (meta && e.key === "k") {
 63→        e.preventDefault();
 64→        document.querySelector<HTMLInputElement>('input[placeholder*="Search"]')?.focus();
 65→      }
 66→      // Ctrl+` = toggle terminal
 67→      if (e.ctrlKey && e.key === "`") {
 68→        e.preventDefault();
 69→        setIsTerminalOpen((v) => !v);
 70→      }
 71→      // Cmd+W = close active tab
 72→      if (meta && e.key === "w") {
 73→        e.preventDefault();
 74→        handleCloseTab(activeTabId);
 75→      }
 76→      // Cmd+1-9 = switch to tab by index
 77→      if (meta && e.key >= "1" && e.key <= "9") {
 78→        e.preventDefault();
 79→        const idx = parseInt(e.key) - 1;
 80→        if (idx < tabs.length) {
 81→          setActiveTabId(tabs[idx].id);
 82→        }
 83→      }
 84→      // Cmd+[ / Cmd+] = prev/next tab
 85→      if (meta && e.key === "[") {
 86→        e.preventDefault();
 87→        const idx = tabs.findIndex((t) => t.id === activeTabId);
 88→        if (idx > 0) setActiveTabId(tabs[idx - 1].id);
 89→      }
 90→      if (meta && e.key === "]") {
 91→        e.preventDefault();
 92→        const idx = tabs.findIndex((t) => t.id === activeTabId);
 93→        if (idx < tabs.length - 1) setActiveTabId(tabs[idx + 1].id);
 94→      }
 95→    }
 96→    window.addEventListener("keydown", onKeyDown);
 97→    return () => window.removeEventListener("keydown", onKeyDown);
 98→  }, [activeTabId, tabs]);
 99→
100→  function handleBranchSelect(branch: BranchInfo, repoPath: string) {
101→    const existing = tabs.find(
102→      (t) => t.branch === branch.name && t.repoPath === repoPath
103→    );
104→    if (existing) {
105→      setActiveTabId(existing.id);
106→    } else {
107→      const newTab: Tab = {
108→        id: `${repoPath}:${branch.name}`,
109→        branch: branch.name,
110→        repoPath,
111→        worktree: null,
112→        hasActiveSession: false,
113→      };
114→      setTabs([...tabs, newTab]);
115→      setActiveTabId(newTab.id);
116→    }
117→  }
118→
119→  function handleWorktreeSelect(wt: WorktreeInfo, repoPath: string) {
120→    const existing = tabs.find(
121→      (t) => t.branch === wt.branch && t.repoPath === repoPath
122→    );
123→    if (existing) {
124→      setActiveTabId(existing.id);
125→    } else {
126→      const newTab: Tab = {
127→        id: `${repoPath}:${wt.branch}`,
128→        branch: wt.branch,
129→        repoPath,
130→        worktree: wt,
131→        hasActiveSession: false,
132→      };
133→      setTabs([...tabs, newTab]);
134→      setActiveTabId(newTab.id);
135→    }
136→  }
137→
138→  function handleCloseTab(tabId: string) {
139→    if (tabs.length <= 1) return;
140→    const idx = tabs.findIndex((t) => t.id === tabId);
141→    const newTabs = tabs.filter((t) => t.id !== tabId);
142→    setTabs(newTabs);
143→    if (activeTabId === tabId) {
144→      setActiveTabId(newTabs[Math.max(0, idx - 1)].id);
145→    }
146→  }
147→
148→  function handleResizeStart(e: React.MouseEvent) {
149→    e.preventDefault();
150→    const startY = e.clientY;
151→    const startHeight = terminalHeight;
152→
153→    function onMouseMove(ev: MouseEvent) {
154→      const delta = startY - ev.clientY;
155→      setTerminalHeight(Math.max(100, Math.min(600, startHeight + delta)));
156→    }
157→    function onMouseUp() {
158→      window.removeEventListener("mousemove", onMouseMove);
159→      window.removeEventListener("mouseup", onMouseUp);
160→    }
161→    window.addEventListener("mousemove", onMouseMove);
162→    window.addEventListener("mouseup", onMouseUp);
163→  }
164→
165→  return (
166→    <div className="flex h-screen flex-col">
167→      <TitleBar title={`Entire — ${activeTab?.branch ?? ""}`} />
168→
169→      <div className="flex flex-1 overflow-hidden">
170→        {/* Sidebar */}
171→        <Sidebar
172→          activeTab={activeTab}
173→          onBranchSelect={handleBranchSelect}
174→          onWorktreeSelect={handleWorktreeSelect}
175→        />
176→
177→        {/* Main content */}
178→        <div className="flex flex-1 flex-col overflow-hidden">
179→          <TabBar
180→            tabs={tabs}
181→            activeTabId={activeTabId}
182→            onSelectTab={setActiveTabId}
183→            onCloseTab={handleCloseTab}
184→          />
185→
186→          <div className="flex flex-1 flex-col overflow-hidden">
187→            {/* Inner tabs */}
188→            <div className="flex gap-0 border-b border-border-subtle bg-bg px-5 pt-3">
189→              {(["checkpoints", "transcript", "trails", "diff"] as const).map((tab) => (
190→                <button
191→                  key={tab}
192→                  onClick={() => setInnerTab(tab)}
193→                  className={`border-b-2 px-4 pb-2 text-xs font-medium capitalize transition-colors ${
194→                    innerTab === tab
195→                      ? "border-accent text-fg"
196→                      : "border-transparent text-fg-subtle hover:text-fg-muted"
197→                  }`}
198→                >
199→                  {tab === "checkpoints"
200→                    ? "Checkpoints"
201→                    : tab === "transcript"
202→                      ? "Transcript"
203→                      : tab === "trails"
204→                        ? "Trails"
205→                        : "Diff"}
206→                </button>
207→              ))}
208→            </div>
209→
210→            {/* Main view */}
211→            <div className="flex-1 overflow-y-auto bg-bg">
212→              {innerTab === "checkpoints" && (
213→                <CheckpointList
214→                  repoPath={activeTab.repoPath}
215→                  branch={activeTab.branch}
216→                  onSelectCheckpoint={(cp) => {
217→                    setSelectedCheckpoint(cp);
218→                    setInnerTab("transcript");
219→                  }}
220→                />
221→              )}
222→              {innerTab === "transcript" && (
223→                <TranscriptView
224→                  repoPath={activeTab.repoPath}
225→                  checkpoint={selectedCheckpoint}
226→                />
227→              )}
228→              {innerTab === "trails" && (
229→                <TrailList repoPath={activeTab.repoPath} />
230→              )}
231→              {innerTab === "diff" && (
232→                <div className="flex items-center justify-center p-20 text-fg-subtle">
233→                  Diff viewer coming soon
234→                </div>
235→              )}
236→            </div>
237→
238→            {/* Resize handle */}
239→            {isTerminalOpen && (
240→              <div
241→                onMouseDown={handleResizeStart}
242→                className="h-[3px] shrink-0 cursor-row-resize bg-border transition-colors hover:bg-accent"
243→              />
244→            )}
245→
246→            {/* Terminal panel */}
247→            {isTerminalOpen && (
248→              <TerminalPanel
249→                height={terminalHeight}
250→                tab={activeTab}
251→                onToggle={() => setIsTerminalOpen(false)}
252→              />
253→            )}
254→          </div>
255→        </div>
256→      </div>
257→
258→      {!isTerminalOpen && (
259→        <button
260→          onClick={() => setIsTerminalOpen(true)}
261→          className="flex h-7 shrink-0 items-center justify-center border-t border-border bg-bg-raised text-[11px] text-fg-subtle hover:text-fg-muted"
262→        >
263→          ▲ Terminal (⌃`)
264→        </button>
265→      )}
266→    </div>
267→  );
268→}
