 1→import { useQuery } from "@tanstack/react-query";
 2→import { invoke } from "@tauri-apps/api/core";
 3→import type { RepoInfo, CheckpointSummary, TranscriptMessage, Trail } from "../lib/ipc";
 4→
 5→export function useReposQuery() {
 6→  return useQuery<RepoInfo[]>({
 7→    queryKey: ["repos"],
 8→    queryFn: () => invoke("list_repos"),
 9→    retry: false,
10→  });
11→}
