13→export function useCheckpointsQuery(repoPath: string, branch: string) {
14→  return useQuery<CheckpointSummary[]>({
15→    queryKey: ["checkpoints", repoPath, branch],
16→    queryFn: () => invoke("list_checkpoints", { repoPath, branch }),
17→    enabled: !!repoPath,
18→    retry: false,
19→  });
20→}
21→
22→export function useTranscriptQuery(
23→  repoPath: string,
24→  checkpointId: string,
25→  sessionIndex: number
26→) {
27→  return useQuery<TranscriptMessage[]>({
28→    queryKey: ["transcript", repoPath, checkpointId, sessionIndex],
29→    queryFn: () =>
30→      invoke("get_transcript", { repoPath, checkpointId, sessionIndex }),
31→    enabled: !!repoPath && !!checkpointId,
32→    retry: false,
33→  });
34→}
35→
36→export function useTrailsQuery(repoPath: string) {
37→  return useQuery<Trail[]>({
38→    queryKey: ["trails", repoPath],
39→    queryFn: () => invoke("list_trails", { repoPath }),
40→    enabled: !!repoPath,
41→    retry: false,
42→  });
