import { useState } from "react";
import {
  GitPullRequest,
  MessageSquare,
  GitCommit,
  Loader2,
  ChevronRight,
} from "lucide-react";
import { useTrailsQuery } from "../../hooks/use-tauri-query";
import type { Trail } from "../../lib/ipc";

interface TrailListProps {
  repoPath: string;
  onSelectTrail?: (trail: Trail) => void;
}

const STATUS_COLORS: Record<string, { dot: string; bg: string; text: string }> = {
  draft: { dot: "bg-fg-subtle", bg: "bg-bg-hover", text: "text-fg-muted" },
  open: { dot: "bg-green", bg: "bg-green-bg", text: "text-green" },
  in_progress: { dot: "bg-blue", bg: "bg-blue-bg", text: "text-blue" },
  in_review: { dot: "bg-yellow", bg: "bg-yellow-bg", text: "text-yellow" },
  merged: { dot: "bg-accent", bg: "bg-accent-bg", text: "text-accent-fg" },
  closed: { dot: "bg-red", bg: "bg-red-bg", text: "text-red" },
};

const PRIORITY_LABELS: Record<string, { label: string; color: string }> = {
  urgent: { label: "Urgent", color: "text-red" },
  high: { label: "High", color: "text-yellow" },
  medium: { label: "Medium", color: "text-blue" },
  low: { label: "Low", color: "text-fg-subtle" },
};

// Mock trails for demo
const MOCK_TRAILS: Trail[] = [
  {
    metadata: {
      trail_id: "a1b2c3d4e5f6",
      branch: "feat-auth",
      base: "main",
      title: "Add JWT authentication",
      body: "Implement JWT-based authentication with refresh token rotation.",
      status: "open",
      author: "alisha",
      assignees: ["alisha"],
      labels: ["feature", "auth"],
      created_at: new Date(Date.now() - 2 * 3600000).toISOString(),
      updated_at: new Date(Date.now() - 30 * 60000).toISOString(),
      merged_at: null,
      priority: "high",
      trail_type: "feature",
      reviewers: [{ login: "patrick", status: "pending" }],
    },
    checkpoint_count: 5,
    comment_count: 3,
  },
  {
    metadata: {
      trail_id: "b2c3d4e5f6a1",
      branch: "fix-null-check",
      base: "main",
      title: "Fix null pointer in user handler",
      body: "Fixes #42 — null deref when user profile is empty.",
      status: "in_review",
      author: "alisha",
      assignees: ["alisha"],
      labels: ["bug"],
      created_at: new Date(Date.now() - 5 * 3600000).toISOString(),
      updated_at: new Date(Date.now() - 60 * 60000).toISOString(),
      merged_at: null,
      priority: "urgent",
      trail_type: "bug",
      reviewers: [{ login: "sven", status: "changes_requested" }],
    },
    checkpoint_count: 3,
    comment_count: 7,
  },
  {
    metadata: {
      trail_id: "c3d4e5f6a1b2",
      branch: "refactor-db",
      base: "main",
      title: "Refactor database connection pool",
      body: "Move from per-request connections to a shared pool.",
      status: "draft",
      author: "alisha",
      assignees: [],
      labels: ["refactor"],
      created_at: new Date(Date.now() - 24 * 3600000).toISOString(),
      updated_at: new Date(Date.now() - 24 * 3600000).toISOString(),
      merged_at: null,
      priority: "medium",
      trail_type: "refactor",
      reviewers: [],
    },
    checkpoint_count: 0,
    comment_count: 0,
  },
];

function timeAgo(isoDate: string): string {
  const diff = Date.now() - new Date(isoDate).getTime();
  const mins = Math.floor(diff / 60000);
  if (mins < 1) return "just now";
  if (mins < 60) return `${mins}m ago`;
  const hours = Math.floor(mins / 60);
  if (hours < 24) return `${hours}h ago`;
  return `${Math.floor(hours / 24)}d ago`;
}

export function TrailList({ repoPath, onSelectTrail }: TrailListProps) {
  const { data: realTrails, isLoading } = useTrailsQuery(repoPath);
  const trails = realTrails && realTrails.length > 0 ? realTrails : MOCK_TRAILS;

  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [statusFilter, setStatusFilter] = useState<string | null>(null);

  const filtered = statusFilter
    ? trails.filter((t) => t.metadata.status === statusFilter)
    : trails;

  const statuses = [...new Set(trails.map((t) => t.metadata.status))];

  return (
    <div>
      {/* Filter chips */}
      <div className="flex gap-1.5 px-5 pt-4 pb-2 overflow-x-auto">
        <button
          onClick={() => setStatusFilter(null)}
          className={`shrink-0 rounded-full px-3 py-1 text-[11px] font-medium transition-colors ${
            !statusFilter
              ? "bg-accent text-white"
              : "bg-bg-overlay text-fg-muted hover:bg-bg-hover"
          }`}
        >
          All ({trails.length})
        </button>
        {statuses.map((status) => {
          const colors = STATUS_COLORS[status] ?? STATUS_COLORS.draft;
          const count = trails.filter((t) => t.metadata.status === status).length;
          return (
            <button
              key={status}
              onClick={() => setStatusFilter(statusFilter === status ? null : status)}
              className={`flex shrink-0 items-center gap-1.5 rounded-full px-3 py-1 text-[11px] font-medium transition-colors ${
                statusFilter === status
                  ? `${colors.bg} ${colors.text}`
                  : "bg-bg-overlay text-fg-muted hover:bg-bg-hover"
              }`}
            >
              <span className={`h-1.5 w-1.5 rounded-full ${colors.dot}`} />
              {status.replace("_", " ")} ({count})
            </button>
          );
        })}
        {isLoading && <Loader2 size={14} className="animate-spin text-fg-subtle ml-2 self-center" />}
      </div>

      {/* Trail list */}
      <div className="px-5 pb-5 pt-2">
        {filtered.map((trail) => {
          const m = trail.metadata;
          const colors = STATUS_COLORS[m.status] ?? STATUS_COLORS.draft;
          const priority = PRIORITY_LABELS[m.priority];

          return (
            <button
              key={m.trail_id}
              onClick={() => {
                setSelectedId(m.trail_id);
                onSelectTrail?.(trail);
              }}
              className={`mb-2 flex w-full gap-3 rounded-[10px] border p-4 text-left transition-all ${
                selectedId === m.trail_id
                  ? "border-accent bg-accent-bg"
                  : "border-border-subtle bg-bg-overlay hover:border-border-hover hover:bg-bg-hover"
              }`}
            >
              {/* Status icon */}
              <div className={`flex h-8 w-8 shrink-0 items-center justify-center rounded-full ${colors.bg}`}>
                <GitPullRequest size={16} className={colors.text} />
              </div>

              {/* Content */}
              <div className="min-w-0 flex-1">
                <div className="mb-1 flex items-center gap-2">
                  <span className="text-[13px] font-medium text-fg">
                    {m.title}
                  </span>
                  <span className={`shrink-0 rounded-full px-2 py-0.5 text-[10px] font-medium ${colors.bg} ${colors.text}`}>
                    {m.status.replace("_", " ")}
                  </span>
                  {priority && (
                    <span className={`text-[10px] font-medium ${priority.color}`}>
                      {priority.label}
                    </span>
                  )}
                </div>

                <div className="mb-2 text-xs text-fg-muted">
                  <span className="font-mono text-fg-subtle">{m.branch}</span>
                  <span className="mx-1.5">→</span>
                  <span className="font-mono text-fg-subtle">{m.base}</span>
                </div>

                <div className="flex gap-4 text-[11px] text-fg-subtle">
                  <span className="flex items-center gap-1">
                    <GitCommit size={11} />
                    {trail.checkpoint_count} checkpoints
                  </span>
                  <span className="flex items-center gap-1">
                    <MessageSquare size={11} />
                    {trail.comment_count} comments
                  </span>
                  {m.labels.map((label) => (
                    <span
                      key={label}
                      className="rounded bg-bg-hover px-1.5 py-0.5 text-[10px]"
                    >
                      {label}
                    </span>
                  ))}
                </div>
              </div>

              {/* Right side */}
              <div className="flex shrink-0 flex-col items-end gap-1">
                <span className="text-[11px] text-fg-subtle">
                  {timeAgo(m.updated_at)}
                </span>
                {m.reviewers.length > 0 && (
                  <div className="flex gap-1">
                    {m.reviewers.map((r) => (
                      <span
                        key={r.login}
                        className={`rounded-full px-1.5 py-0.5 text-[9px] font-medium ${
                          r.status === "approved"
                            ? "bg-green-bg text-green"
                            : r.status === "changes_requested"
                              ? "bg-yellow-bg text-yellow"
                              : "bg-bg-hover text-fg-subtle"
                        }`}
                      >
                        {r.login}
                      </span>
                    ))}
                  </div>
                )}
                <ChevronRight size={14} className="text-fg-faint" />
              </div>
            </button>
          );
        })}

        {filtered.length === 0 && !isLoading && (
          <div className="py-12 text-center text-sm text-fg-subtle">
            No trails found
          </div>
        )}
      </div>
    </div>
  );
}

