139→#[tauri::command]
140→fn watch_repo(
141→    repo_path: String,
142→    app: tauri::AppHandle,
143→    state: State<'_, Mutex<AppState>>,
144→) -> Result<(), String> {
145→    let mut app_state = state.lock().map_err(|_| "State lock error".to_string())?;
146→
147→    // Don't double-watch
148→    if app_state.watched_repos.contains(&repo_path) {
149→        return Ok(());
150→    }
151→    app_state.watched_repos.insert(repo_path.clone());
152→
153→    let app_handle = app.clone();
154→    let repo_path_for_closure = repo_path.clone();
155→    watcher::watch_repo(&repo_path, move |event| {
156→        let event_name = match event {
157→            watcher::WatchEvent::CheckpointChanged => "checkpoint-changed",
158→            watcher::WatchEvent::SessionChanged(_) => "session-changed",
159→            watcher::WatchEvent::ConfigChanged => "config-changed",
160→        };
161→        let _ = app_handle.emit(event_name, serde_json::json!({
162→            "repoPath": repo_path_for_closure,
163→        }));
164→    })?;
165→
166→    Ok(())
167→}
