169→#[cfg_attr(mobile, tauri::mobile_entry_point)]
170→pub fn run() {
171→    tauri::Builder::default()
172→        .plugin(tauri_plugin_opener::init())
173→        .plugin(tauri_plugin_window_state::Builder::default().build())
174→        .manage(Mutex::new(AppState {
175→            pty_manager: pty::PtyManager::new(),
176→            watched_repos: HashSet::new(),
177→        }))
178→        .setup(|app| {
179→            // System tray
180→            use tauri::menu::{MenuBuilder, MenuItemBuilder};
181→            use tauri::tray::TrayIconBuilder;
182→            use tauri::Manager;
183→
184→            let show = MenuItemBuilder::with_id("show", "Show Entire").build(app)?;
185→            let quit = MenuItemBuilder::with_id("quit", "Quit").build(app)?;
186→            let menu = MenuBuilder::new(app)
187→                .item(&show)
188→                .separator()
189→                .item(&quit)
190→                .build()?;
191→
192→            let _tray = TrayIconBuilder::new()
193→                .tooltip("Entire Desktop")
194→                .menu(&menu)
195→                .on_menu_event(move |app, event| {
196→                    match event.id().as_ref() {
197→                        "show" => {
198→                            if let Some(window) = app.get_webview_window("main") {
199→                                let _ = window.show();
200→                                let _ = window.set_focus();
201→                            }
202→                        }
203→                        "quit" => {
204→                            app.exit(0);
205→                        }
206→                        _ => {}
207→                    }
208→                })
209→                .on_tray_icon_event(|tray, event| {
210→                    if let tauri::tray::TrayIconEvent::Click { .. } = event {
211→                        let app = tray.app_handle();
212→                        if let Some(window) = app.get_webview_window("main") {
213→                            let _ = window.show();
214→                            let _ = window.set_focus();
215→                        }
216→                    }
217→                })
218→                .build(app)?;
219→
220→            Ok(())
221→        })
222→        .invoke_handler(tauri::generate_handler![
223→            list_repos,
224→            list_checkpoints,
225→            get_transcript,
226→            list_sessions,
227→            spawn_agent,
228→            pty_input,
229→            pty_resize,
230→            kill_pty,
231→            list_trails,
232→            watch_repo,
233→        ])
234→        .run(tauri::generate_context!())
235→        .expect("error while running tauri application");
236→}
