26→/// Check if a repo has Entire enabled
27→pub fn is_entire_enabled(repo_path: &str) -> bool {
28→    let entire_dir = Path::new(repo_path).join(".entire");
29→    if !entire_dir.exists() {
30→        return false;
31→    }
