38→/// Discover repos with Entire enabled by scanning common directories
39→pub fn discover_repos() -> Vec<String> {
40→    let mut repos = Vec::new();
41→    let home = dirs_next().unwrap_or_default();
42→
43→    // Scan common project directories
44→    let scan_dirs = vec![
45→        PathBuf::from(&home).join("Projects"),
46→        PathBuf::from(&home).join("code"),
47→        PathBuf::from(&home).join("src"),
48→        PathBuf::from(&home).join("dev"),
49→    ];
50→
51→    for dir in scan_dirs {
52→        if dir.exists() {
53→            if let Ok(entries) = fs::read_dir(&dir) {
54→                for entry in entries.flatten() {
55→                    let path = entry.path();
56→                    if path.is_dir() && is_entire_enabled(&path.to_string_lossy()) {
57→                        repos.push(path.to_string_lossy().to_string());
58→                    }
59→                }
60→            }
61→        }
62→    }
63→
64→    repos
65→}
