 81→/// List all checkpoints from the entire/checkpoints/v1 branch
 82→pub fn list_checkpoints(
 83→    repo: &Repository,
 84→    filter_branch: &str,
 85→) -> Result<Vec<CheckpointSummary>, String> {
 86→    let branch_ref = match repo.find_branch("entire/checkpoints/v1", git2::BranchType::Local) {
 87→        Ok(b) => b,
 88→        Err(_) => return Ok(Vec::new()), // No checkpoints branch yet
 89→    };
 90→
 91→    let commit = branch_ref
 92→        .get()
 93→        .peel_to_commit()
 94→        .map_err(|e| format!("Failed to get checkpoint commit: {}", e))?;
 95→
 96→    let tree = commit
 97→        .tree()
 98→        .map_err(|e| format!("Failed to get tree: {}", e))?;
 99→
100→    let mut checkpoints = Vec::new();
101→
102→    // Walk the sharded directory structure: <id[:2]>/<id[2:]>/metadata.json
103→    tree.walk(git2::TreeWalkMode::PreOrder, |dir, entry| {
104→        let name = match entry.name() {
105→            Some(n) => n,
106→            None => return git2::TreeWalkResult::Ok,
107→        };
108→
109→        // Look for metadata.json at the checkpoint level (e.g., "a1/b2c3d4/metadata.json")
110→        if name == "metadata.json" && !dir.is_empty() {
111→            // dir looks like "a1/b2c3d4/" — that's 2 levels deep
112→            let parts: Vec<&str> = dir.trim_end_matches('/').split('/').collect();
113→            if parts.len() == 2 {
114→                // This is a root checkpoint metadata.json
115→                if let Ok(blob) = repo.find_blob(entry.id()) {
116→                    if let Ok(content) = std::str::from_utf8(blob.content()) {
117→                        if let Ok(meta) = serde_json::from_str::<RawCheckpointMetadata>(content) {
118→                            let branch = meta.branch.clone().unwrap_or_default();
119→                            if filter_branch.is_empty() || branch == filter_branch {
120→                                let cp = build_checkpoint_summary(
121→                                    repo,
122→                                    &tree,
123→                                    dir,
124→                                    &meta,
125→                                );
126→                                if let Ok(cp) = cp {
127→                                    checkpoints.push(cp);
128→                                }
129→                            }
130→                        }
131→                    }
132→                }
133→            }
134→        }
135→
136→        git2::TreeWalkResult::Ok
137→    })
138→    .map_err(|e| format!("Tree walk error: {}", e))?;
139→
140→    // Sort by created_at descending
141→    checkpoints.sort_by(|a, b| b.created_at.cmp(&a.created_at));
142→
143→    Ok(checkpoints)
144→}
145→
146→fn build_checkpoint_summary(
147→    repo: &Repository,
148→    _tree: &git2::Tree,
149→    dir: &str,
150→    meta: &RawCheckpointMetadata,
151→) -> Result<CheckpointSummary, String> {
152→    let checkpoint_id = meta
153→        .checkpoint_id
154→        .clone()
155→        .unwrap_or_else(|| dir.replace('/', ""));
156→
157→    let mut sessions = Vec::new();
158→
159→    // Read session metadata from subdirectories (1/, 2/, etc.)
160→    if let Some(refs) = &meta.sessions {
161→        for (i, _session_ref) in refs.iter().enumerate() {
162→            let session_dir = format!("{}{}/", dir, i + 1);
163→            let session_meta_path = format!("{}metadata.json", session_dir);
164→
165→            // Try to read session metadata from the tree
166→            if let Ok(session_meta) = read_blob_from_tree(repo, &session_meta_path) {
167→                if let Ok(sm) = serde_json::from_str::<RawSessionMetadata>(&session_meta) {
168→                    sessions.push(SessionSummary {
169→                        session_id: sm.session_id.unwrap_or_default(),
170→                        agent: sm.agent.unwrap_or_else(|| "Unknown".to_string()),
171→                        model: sm.model,
172→                        step_count: 0, // TODO: count from transcript
173→                        summary: sm.summary,
174→                        token_usage: sm.token_usage,
175→                        initial_attribution: sm.initial_attribution,
176→                    });
177→                }
178→            }
179→        }
180→    }
181→
182→    Ok(CheckpointSummary {
183→        checkpoint_id,
184→        branch: meta.branch.clone().unwrap_or_default(),
185→        commit_sha: String::new(), // TODO: resolve from commit trailer
186→        commit_message: String::new(), // TODO: resolve from commit
187→        files_touched: meta.files_touched.clone().unwrap_or_default(),
188→        sessions,
189→        token_usage: meta.token_usage.clone(),
190→        created_at: String::new(), // TODO: from session metadata
191→    })
192→}
193→
194→fn read_blob_from_tree(repo: &Repository, path: &str) -> Result<String, String> {
195→    let branch_ref = repo
196→        .find_branch("entire/checkpoints/v1", git2::BranchType::Local)
197→        .map_err(|e| format!("No checkpoint branch: {}", e))?;
198→
199→    let commit = branch_ref
200→        .get()
201→        .peel_to_commit()
202→        .map_err(|e| format!("Failed to peel: {}", e))?;
203→
204→    let tree = commit
205→        .tree()
206→        .map_err(|e| format!("Failed to get tree: {}", e))?;
207→
208→    let entry = tree
209→        .get_path(std::path::Path::new(path))
210→        .map_err(|e| format!("Path not found: {}", e))?;
211→
212→    let blob = repo
213→        .find_blob(entry.id())
214→        .map_err(|e| format!("Failed to read blob: {}", e))?;
215→
216→    std::str::from_utf8(blob.content())
217→        .map(|s| s.to_string())
218→        .map_err(|e| format!("Invalid UTF-8: {}", e))
219→}
