 20→    pub files_touched: Option<Vec<String>>,
 21→}
 22→
 23→#[derive(Debug, Serialize, Clone)]
 24→pub struct TranscriptMessage {
 25→    pub role: String,
 26→    pub content: String,
 27→    pub tool_name: Option<String>,
 28→    pub tool_input: Option<String>,
 29→    pub timestamp: Option<String>,
 30→}
 31→
 32→/// Find the git common dir (handles worktrees)
 33→fn git_common_dir(repo_path: &str) -> PathBuf {
 34→    let git_dir = Path::new(repo_path).join(".git");
 35→    if git_dir.is_file() {
 36→        // Worktree: .git is a file containing "gitdir: /path/to/worktree/git"
 37→        if let Ok(content) = fs::read_to_string(&git_dir) {
 38→            if let Some(gitdir) = content.strip_prefix("gitdir: ") {
 39→                let gitdir = gitdir.trim();
 40→                let gitdir_path = if Path::new(gitdir).is_absolute() {
 41→                    PathBuf::from(gitdir)
 42→                } else {
 43→                    Path::new(repo_path).join(gitdir)
 44→                };
 45→                // commondir file tells us where the shared git dir is
 46→                let commondir_file = gitdir_path.join("commondir");
 47→                if let Ok(commondir) = fs::read_to_string(&commondir_file) {
 48→                    let commondir = commondir.trim();
 49→                    if Path::new(commondir).is_absolute() {
 50→                        return PathBuf::from(commondir);
 51→                    } else {
 52→                        return gitdir_path.join(commondir);
 53→                    }
 54→                }
 55→                return gitdir_path;
 56→            }
 57→        }
 58→    }
 59→    git_dir
 60→}
 61→
 62→/// List active sessions from .git/entire-sessions/
 63→pub fn list_active_sessions(repo_path: &str) -> Result<Vec<SessionState>, String> {
 64→    let sessions_dir = git_common_dir(repo_path).join("entire-sessions");
 65→    if !sessions_dir.exists() {
 66→        return Ok(Vec::new());
 67→    }
 68→
 69→    let mut sessions = Vec::new();
 70→    let entries =
 71→        fs::read_dir(&sessions_dir).map_err(|e| format!("Failed to read sessions dir: {}", e))?;
 72→
 73→    for entry in entries {
 74→        let entry = entry.map_err(|e| format!("Dir entry error: {}", e))?;
 75→        let path = entry.path();
 76→        if path.extension().map_or(false, |ext| ext == "json") {
 77→            if let Ok(content) = fs::read_to_string(&path) {
 78→                if let Ok(state) = serde_json::from_str::<SessionState>(&content) {
 79→                    sessions.push(state);
 80→                }
 81→            }
 82→        }
 83→    }
 84→
 85→    Ok(sessions)
 86→}
 87→
 88→/// Read transcript from checkpoint data (JSONL format)
 89→pub fn read_transcript(content: &str) -> Vec<TranscriptMessage> {
 90→    let mut messages = Vec::new();
 91→
 92→    for line in content.lines() {
 93→        if line.trim().is_empty() {
 94→            continue;
 95→        }
 96→        if let Ok(value) = serde_json::from_str::<serde_json::Value>(line) {
 97→            // Claude Code JSONL format: each line has a message object
 98→            let role = value
 99→                .get("role")
100→                .and_then(|r| r.as_str())
101→                .unwrap_or("unknown")
102→                .to_string();
103→
104→            let content_text = extract_content_text(&value);
105→
106→            let tool_name = value
107→                .get("tool_name")
108→                .or_else(|| value.get("name"))
109→                .and_then(|n| n.as_str())
110→                .map(|s| s.to_string());
111→
112→            let tool_input = value
113→                .get("tool_input")
114→                .or_else(|| value.get("input"))
115→                .map(|v| {
116→                    if v.is_string() {
117→                        v.as_str().unwrap_or("").to_string()
118→                    } else {
119→                        serde_json::to_string(v).unwrap_or_default()
120→                    }
121→                });
122→
123→            if !content_text.is_empty() || tool_name.is_some() {
124→                messages.push(TranscriptMessage {
125→                    role,
126→                    content: content_text,
127→                    tool_name,
128→                    tool_input,
129→                    timestamp: None,
130→                });
131→            }
132→        }
133→    }
134→
135→    messages
136→}
137→
138→fn extract_content_text(value: &serde_json::Value) -> String {
139→    if let Some(content) = value.get("content") {
140→        if let Some(text) = content.as_str() {
141→            return text.to_string();
142→        }
143→        if let Some(arr) = content.as_array() {
144→            let mut parts = Vec::new();
145→            for item in arr {
146→                if let Some(text) = item.get("text").and_then(|t| t.as_str()) {
147→                    parts.push(text.to_string());
148→                }
149→            }
150→            return parts.join("\n");
151→        }
152→    }
153→    String::new()
154→}
