mod checkpoint;
mod config;
mod git;
mod pty;
mod session;
mod trail;
mod watcher;

use std::collections::HashSet;
use std::sync::Mutex;
use tauri::{Emitter, Manager, State};

struct AppState {
    pty_manager: pty::PtyManager,
    watched_repos: HashSet<String>,
}

#[tauri::command]
fn list_repos() -> Result<Vec<git::RepoInfo>, String> {
    let repo_paths = config::discover_repos();
    let mut repos = Vec::new();
    for path in repo_paths {
        match git::get_repo_info(&path) {
            Ok(info) => repos.push(info),
            Err(e) => eprintln!("Skipping repo {}: {}", path, e),
        }
    }
    Ok(repos)
}

#[tauri::command]
fn list_checkpoints(
    repo_path: String,
    branch: String,
) -> Result<Vec<checkpoint::CheckpointSummary>, String> {
    let repo = git::open_repo(&repo_path)?;
    checkpoint::list_checkpoints(&repo, &branch)
}

#[tauri::command]
fn get_transcript(
    repo_path: String,
    checkpoint_id: String,
    session_index: u32,
) -> Result<Vec<session::TranscriptMessage>, String> {
    let repo = git::open_repo(&repo_path)?;

    // Read transcript from checkpoint branch
    let prefix = &checkpoint_id[..2];
    let suffix = &checkpoint_id[2..];
    let transcript_path = format!("{}/{}/{}/full.jsonl", prefix, suffix, session_index + 1);

    let branch_ref = repo
        .find_branch("entire/checkpoints/v1", git2::BranchType::Local)
        .map_err(|e| format!("No checkpoint branch: {}", e))?;

    let commit = branch_ref
        .get()
        .peel_to_commit()
        .map_err(|e| format!("Failed to peel: {}", e))?;

    let tree = commit
        .tree()
        .map_err(|e| format!("Failed to get tree: {}", e))?;

    let entry = tree
        .get_path(std::path::Path::new(&transcript_path))
        .map_err(|e| format!("Transcript not found: {}", e))?;

    let blob = repo
        .find_blob(entry.id())
        .map_err(|e| format!("Failed to read blob: {}", e))?;

    let content = std::str::from_utf8(blob.content())
        .map_err(|e| format!("Invalid UTF-8: {}", e))?;

    Ok(session::read_transcript(content))
}

#[tauri::command]
fn list_sessions(repo_path: String) -> Result<Vec<session::SessionState>, String> {
    session::list_active_sessions(&repo_path)
}

#[tauri::command]
fn spawn_agent(
    repo_path: String,
    agent: String,
    app: tauri::AppHandle,
    state: State<'_, Mutex<AppState>>,
) -> Result<String, String> {
    let app_handle = app.clone();
    let state = state.lock().map_err(|_| "State lock error".to_string())?;

    state.pty_manager.spawn(&agent, &repo_path, move |session_id, data| {
        let _ = app_handle.emit("pty-output", serde_json::json!({
            "sessionId": session_id,
            "data": data,
        }));
    })
}

#[tauri::command]
fn pty_input(
    session_id: String,
    data: String,
    state: State<'_, Mutex<AppState>>,
) -> Result<(), String> {
    let state = state.lock().map_err(|_| "State lock error".to_string())?;
    state.pty_manager.write(&session_id, data.as_bytes())
}

#[tauri::command]
fn pty_resize(
    session_id: String,
    cols: u16,
    rows: u16,
    state: State<'_, Mutex<AppState>>,
) -> Result<(), String> {
    let state = state.lock().map_err(|_| "State lock error".to_string())?;
    state.pty_manager.resize(&session_id, cols, rows)
}

#[tauri::command]
fn kill_pty(
    session_id: String,
    state: State<'_, Mutex<AppState>>,
) -> Result<(), String> {
    let state = state.lock().map_err(|_| "State lock error".to_string())?;
    state.pty_manager.kill(&session_id)
}

#[tauri::command]
fn list_trails(repo_path: String) -> Result<Vec<trail::Trail>, String> {
    let repo = git::open_repo(&repo_path)?;
    trail::list_trails(&repo)
}

#[tauri::command]
fn watch_repo(
    repo_path: String,
    app: tauri::AppHandle,
    state: State<'_, Mutex<AppState>>,
) -> Result<(), String> {
    let mut app_state = state.lock().map_err(|_| "State lock error".to_string())?;

    // Don't double-watch
    if app_state.watched_repos.contains(&repo_path) {
        return Ok(());
    }
    app_state.watched_repos.insert(repo_path.clone());

    let app_handle = app.clone();
    let repo_path_for_closure = repo_path.clone();
    watcher::watch_repo(&repo_path, move |event| {
        let event_name = match event {
            watcher::WatchEvent::CheckpointChanged => "checkpoint-changed",
