struct FileDiff {
    path: String,
    status: String, // "added", "modified", "deleted"
    hunks: Vec<DiffHunk>,
}

#[derive(serde::Serialize)]
struct DiffHunk {
    header: String,
    lines: Vec<DiffLine>,
}

#[derive(serde::Serialize)]
struct DiffLine {
    kind: String, // "add", "delete", "context"
    content: String,
}

#[tauri::command]
fn get_checkpoint_diff(
    repo_path: String,
    commit_sha: String,
) -> Result<Vec<FileDiff>, String> {
    if commit_sha.is_empty() {
        return Err("No commit SHA available for this checkpoint".to_string());
    }

    let repo = git::open_repo(&repo_path)?;
    let oid = git2::Oid::from_str(&commit_sha)
        .map_err(|e| format!("Invalid commit SHA: {}", e))?;
    let commit = repo
        .find_commit(oid)
        .map_err(|e| format!("Commit not found: {}", e))?;

    let tree = commit
        .tree()
        .map_err(|e| format!("Failed to get tree: {}", e))?;

    // Diff against parent (or empty tree if no parent)
    let parent_tree = commit
        .parent(0)
        .ok()
        .and_then(|p| p.tree().ok());

    let diff = repo
        .diff_tree_to_tree(parent_tree.as_ref(), Some(&tree), None)
        .map_err(|e| format!("Failed to compute diff: {}", e))?;

    let mut files: Vec<FileDiff> = Vec::new();

    diff.print(git2::DiffFormat::Patch, |delta, hunk, line| {
        let path = delta
            .new_file()
            .path()
            .or_else(|| delta.old_file().path())
            .map(|p| p.to_string_lossy().to_string())
            .unwrap_or_default();

        let status = match delta.status() {
            git2::Delta::Added => "added",
            git2::Delta::Deleted => "deleted",
            _ => "modified",
        };

        // Ensure we have a FileDiff entry for this path
        if files.last().map_or(true, |f| f.path != path) {
            files.push(FileDiff {
                path: path.clone(),
                status: status.to_string(),
                hunks: Vec::new(),
            });
        }

        let file = files.last_mut().unwrap();

        // New hunk
        if let Some(h) = hunk {
            let header = std::str::from_utf8(h.header()).unwrap_or("").to_string();
            if file.hunks.last().map_or(true, |last| last.header != header) {
                file.hunks.push(DiffHunk {
                    header,
                    lines: Vec::new(),
                });
            }
        }

        // Diff line
        if let Some(current_hunk) = file.hunks.last_mut() {
            let kind = match line.origin() {
                '+' => "add",
                '-' => "delete",
                ' ' => "context",
                _ => return true,
            };
            let content = std::str::from_utf8(line.content()).unwrap_or("").to_string();
            current_hunk.lines.push(DiffLine {
                kind: kind.to_string(),
                content,
            });
        }

        true
    })
    .map_err(|e| format!("Failed to print diff: {}", e))?;

    Ok(files)
}

