import { useState } from "react";
import {
  FileCode,
  FilePlus,
  FileMinus,
  ChevronDown,
  ChevronRight,
  Loader2,
  GitCommit,
} from "lucide-react";
import { useDiffQuery } from "../../hooks/use-tauri-query";
import type { CheckpointSummary, FileDiff } from "../../lib/ipc";

interface DiffViewProps {
  repoPath: string;
  checkpoint: CheckpointSummary | null;
}

const STATUS_CONFIG = {
  added: { icon: FilePlus, color: "text-green", bg: "bg-green-bg", label: "Added" },
  deleted: { icon: FileMinus, color: "text-red", bg: "bg-red-bg", label: "Deleted" },
  modified: { icon: FileCode, color: "text-yellow", bg: "bg-yellow-bg", label: "Modified" },
} as const;

function FileEntry({
  file,
  defaultExpanded,
}: {
  file: FileDiff;
  defaultExpanded: boolean;
}) {
  const [expanded, setExpanded] = useState(defaultExpanded);
  const config = STATUS_CONFIG[file.status] || STATUS_CONFIG.modified;
  const Icon = config.icon;

  const additions = file.hunks.reduce(
    (sum, h) => sum + h.lines.filter((l) => l.kind === "add").length,
    0
  );
  const deletions = file.hunks.reduce(
    (sum, h) => sum + h.lines.filter((l) => l.kind === "delete").length,
    0
  );

  return (
    <div className="mb-2 overflow-hidden rounded-lg border border-border-subtle">
      {/* File header */}
      <button
        onClick={() => setExpanded(!expanded)}
        className="flex w-full items-center gap-2 bg-bg-overlay px-3 py-2 text-left transition-colors hover:bg-bg-hover"
      >
        {expanded ? (
          <ChevronDown size={14} className="shrink-0 text-fg-subtle" />
        ) : (
          <ChevronRight size={14} className="shrink-0 text-fg-subtle" />
        )}
        <Icon size={14} className={`shrink-0 ${config.color}`} />
        <span className="min-w-0 flex-1 truncate font-mono text-xs text-fg">
          {file.path}
        </span>
        <span className={`shrink-0 rounded px-1.5 py-0.5 text-[10px] font-medium ${config.bg} ${config.color}`}>
          {config.label}
        </span>
        {additions > 0 && (
          <span className="shrink-0 font-mono text-[11px] text-green">
            +{additions}
          </span>
        )}
        {deletions > 0 && (
          <span className="shrink-0 font-mono text-[11px] text-red">
            -{deletions}
          </span>
        )}
      </button>

      {/* Diff hunks */}
      {expanded && (
        <div className="overflow-x-auto border-t border-border-subtle bg-[#0d0f12]">
          {file.hunks.map((hunk, hi) => (
            <div key={hi}>
              {/* Hunk header */}
              <div className="border-b border-border-subtle/30 bg-accent-bg/20 px-4 py-1 font-mono text-[11px] text-accent-fg/70">
                {hunk.header.trim()}
              </div>
              {/* Lines */}
              <div>
                {hunk.lines.map((line, li) => (
                  <div
                    key={li}
                    className={`flex font-mono text-xs leading-[22px] ${
                      line.kind === "add"
                        ? "bg-green/[0.08] text-green"
                        : line.kind === "delete"
                          ? "bg-red/[0.08] text-red"
                          : "text-fg-subtle"
                    }`}
                  >
                    <span
                      className={`inline-block w-6 shrink-0 select-none text-center text-[10px] leading-[22px] ${
                        line.kind === "add"
                          ? "text-green/50"
                          : line.kind === "delete"
                            ? "text-red/50"
                            : "text-fg-faint"
                      }`}
                    >
                      {line.kind === "add" ? "+" : line.kind === "delete" ? "-" : " "}
                    </span>
                    <pre className="min-w-0 flex-1 whitespace-pre-wrap break-all pr-4">
                      {line.content}
                    </pre>
                  </div>
                ))}
              </div>
            </div>
          ))}
          {file.hunks.length === 0 && (
            <div className="px-4 py-3 text-xs text-fg-subtle">
