/// List all checkpoints from the entire/checkpoints/v1 branch
pub fn list_checkpoints(
    repo: &Repository,
    filter_branch: &str,
) -> Result<Vec<CheckpointSummary>, String> {
    let branch_ref = match repo.find_branch("entire/checkpoints/v1", git2::BranchType::Local) {
        Ok(b) => b,
        Err(_) => return Ok(Vec::new()), // No checkpoints branch yet
    };

    let commit = branch_ref
        .get()
        .peel_to_commit()
        .map_err(|e| format!("Failed to get checkpoint commit: {}", e))?;

    let tree = commit
        .tree()
        .map_err(|e| format!("Failed to get tree: {}", e))?;

    let mut checkpoints = Vec::new();

    // Walk the sharded directory structure: <id[:2]>/<id[2:]>/metadata.json
    tree.walk(git2::TreeWalkMode::PreOrder, |dir, entry| {
        let name = match entry.name() {
            Some(n) => n,
            None => return git2::TreeWalkResult::Ok,
        };

        // Look for metadata.json at the checkpoint level (e.g., "a1/b2c3d4/metadata.json")
        if name == "metadata.json" && !dir.is_empty() {
            // dir looks like "a1/b2c3d4/" — that's 2 levels deep
            let parts: Vec<&str> = dir.trim_end_matches('/').split('/').collect();
            if parts.len() == 2 {
                // This is a root checkpoint metadata.json
                if let Ok(blob) = repo.find_blob(entry.id()) {
                    if let Ok(content) = std::str::from_utf8(blob.content()) {
                        if let Ok(meta) = serde_json::from_str::<RawCheckpointMetadata>(content) {
                            let branch = meta.branch.clone().unwrap_or_default();
                            if filter_branch.is_empty() || branch == filter_branch {
                                let cp = build_checkpoint_summary(
                                    repo,
                                    &tree,
                                    dir,
                                    &meta,
                                );
                                if let Ok(cp) = cp {
                                    checkpoints.push(cp);
                                }
                            }
                        }
                    }
                }
            }
        }

        git2::TreeWalkResult::Ok
    })
    .map_err(|e| format!("Tree walk error: {}", e))?;

    // Sort by created_at descending
    checkpoints.sort_by(|a, b| b.created_at.cmp(&a.created_at));

    Ok(checkpoints)
}

fn build_checkpoint_summary(
    repo: &Repository,
    _tree: &git2::Tree,
    dir: &str,
    meta: &RawCheckpointMetadata,
) -> Result<CheckpointSummary, String> {
    let checkpoint_id = meta
        .checkpoint_id
        .clone()
        .unwrap_or_else(|| dir.replace('/', ""));

    let mut sessions = Vec::new();
    let mut earliest_created_at: Option<String> = None;
    // Read session metadata from subdirectories (1/, 2/, etc.)
    if let Some(refs) = &meta.sessions {
        for (i, session_ref) in refs.iter().enumerate() {
            let session_dir = format!("{}{}/", dir, i + 1);
            let session_meta_path = format!("{}metadata.json", session_dir);

            // Try to read session metadata from the tree
            if let Ok(session_meta) = read_blob_from_tree(repo, &session_meta_path) {
                if let Ok(sm) = serde_json::from_str::<RawSessionMetadata>(&session_meta) {
                    // Track earliest created_at across sessions
                    if let Some(ref ca) = sm.created_at {
                        if earliest_created_at.as_ref().map_or(true, |e| ca < e) {
                            earliest_created_at = Some(ca.clone());
                        }
                    }

                    // Count steps from transcript if available
                    let step_count = count_transcript_steps(repo, session_ref, &session_dir);

                    sessions.push(SessionSummary {
                        session_id: sm.session_id.unwrap_or_default(),
                        agent: sm.agent.unwrap_or_else(|| "Unknown".to_string()),
                        model: sm.model,
                        step_count,
                        summary: sm.summary,
                        token_usage: sm.token_usage,
                        initial_attribution: sm.initial_attribution,
                    });
                }
            }
        }
    }

    // Use checkpoint metadata fields first, fall back to session-derived values
    let created_at = meta
        .created_at
        .clone()
        .or(earliest_created_at)
        .unwrap_or_default();

    Ok(CheckpointSummary {
        checkpoint_id,
        branch: meta.branch.clone().unwrap_or_default(),
        commit_sha: meta.commit_sha.clone().unwrap_or_default(),
        commit_message: meta.commit_message.clone().unwrap_or_default(),
        files_touched: meta.files_touched.clone().unwrap_or_default(),
        sessions,
        token_usage: meta.token_usage.clone(),
        created_at,
    })
}

fn count_transcript_steps(
    repo: &Repository,
    session_ref: &RawSessionRef,
    session_dir: &str,
) -> u32 {
    // Try to read the transcript file and count assistant messages (steps)
    let transcript_path = session_ref
        .transcript
        .as_deref()
        .map(|t| format!("{}{}", session_dir, t))
        .unwrap_or_else(|| format!("{}full.jsonl", session_dir));

    if let Ok(content) = read_blob_from_tree(repo, &transcript_path) {
        content
            .lines()
            .filter(|line| line.contains("\"role\":\"assistant\"") || line.contains("\"role\": \"assistant\""))
            .count() as u32
    } else {
        0
    }
}

fn read_blob_from_tree(repo: &Repository, path: &str) -> Result<String, String> {
    let branch_ref = repo
        .find_branch("entire/checkpoints/v1", git2::BranchType::Local)
        .map_err(|e| format!("No checkpoint branch: {}", e))?;

    let commit = branch_ref
        .get()
        .peel_to_commit()
        .map_err(|e| format!("Failed to peel: {}", e))?;

    let tree = commit
        .tree()
        .map_err(|e| format!("Failed to get tree: {}", e))?;

    let entry = tree
        .get_path(std::path::Path::new(path))
        .map_err(|e| format!("Path not found: {}", e))?;

    let blob = repo
        .find_blob(entry.id())
        .map_err(|e| format!("Failed to read blob: {}", e))?;

    std::str::from_utf8(blob.content())
        .map(|s| s.to_string())
        .map_err(|e| format!("Invalid UTF-8: {}", e))
}

use portable_pty::{native_pty_system, CommandBuilder, PtySize};
use serde::Serialize;
use std::collections::HashMap;
use std::io::{Read, Write};
use std::sync::{Arc, Mutex};

#[derive(Debug, Serialize, Clone)]
pub struct PtySessionInfo {
    pub id: String,
    pub agent: String,
    pub repo_path: String,
}

pub struct PtyManager {
    sessions: Arc<Mutex<HashMap<String, PtySession>>>,
}

struct PtySession {
    writer: Box<dyn Write + Send>,
    master: Box<dyn portable_pty::MasterPty + Send>,
    _child: Box<dyn portable_pty::Child + Send + Sync>,
    info: PtySessionInfo,
}

impl PtyManager {
    pub fn new() -> Self {
        Self {
            sessions: Arc::new(Mutex::new(HashMap::new())),
        }
    }

    pub fn spawn(
        &self,
        agent: &str,
        repo_path: &str,
        event_emitter: impl Fn(String, Vec<u8>) + Send + 'static,
    ) -> Result<String, String> {
        let pty_system = native_pty_system();

        let pair = pty_system
            .openpty(PtySize {
                rows: 24,
                cols: 80,
                pixel_width: 0,
                pixel_height: 0,
            })
            .map_err(|e| format!("Failed to open PTY: {}", e))?;

        let cmd = match agent {
            "claude-code" => {
                let mut cmd = CommandBuilder::new("claude");
                cmd.cwd(repo_path);
                cmd
            }
            "codex" => {
                let mut cmd = CommandBuilder::new("codex");
                cmd.cwd(repo_path);
                cmd
            }
            _ => return Err(format!("Unknown agent: {}", agent)),
        };

        let child = pair
            .slave
            .spawn_command(cmd)
            .map_err(|e| format!("Failed to spawn: {}", e))?;

        let session_id = uuid_v4();
        let writer = pair
            .master
            .take_writer()
            .map_err(|e| format!("Failed to get writer: {}", e))?;

        let info = PtySessionInfo {
            id: session_id.clone(),
            agent: agent.to_string(),
            repo_path: repo_path.to_string(),
        };

        // Spawn reader thread to stream output
        let mut reader = pair
            .master
            .try_clone_reader()
            .map_err(|e| format!("Failed to clone reader: {}", e))?;

        let sid = session_id.clone();
        std::thread::spawn(move || {
            let mut buf = [0u8; 4096];
            loop {
                match reader.read(&mut buf) {
                    Ok(0) => break,
                    Ok(n) => {
                        event_emitter(sid.clone(), buf[..n].to_vec());
                    }
                    Err(_) => break,
                }
            }
        });

        let session = PtySession {
            writer,
            master: pair.master,
            _child: child,
            info,
        };

        self.sessions
            .lock()
            .map_err(|_| "Lock error".to_string())?
            .insert(session_id.clone(), session);

        Ok(session_id)
    }

    pub fn write(&self, session_id: &str, data: &[u8]) -> Result<(), String> {
        let mut sessions = self
            .sessions
            .lock()
            .map_err(|_| "Lock error".to_string())?;
        let session = sessions
            .get_mut(session_id)
            .ok_or_else(|| "Session not found".to_string())?;
        session
            .writer
            .write_all(data)
            .map_err(|e| format!("Write error: {}", e))
    }

    pub fn resize(&self, session_id: &str, cols: u16, rows: u16) -> Result<(), String> {
        let sessions = self
            .sessions
            .lock()
            .map_err(|_| "Lock error".to_string())?;
        let session = sessions
            .get(session_id)
            .ok_or_else(|| "Session not found".to_string())?;
        session
            .master
            .resize(PtySize {
                rows,
                cols,
                pixel_width: 0,
                pixel_height: 0,
            })
            .map_err(|e| format!("Resize error: {}", e))
    }

    pub fn kill(&self, session_id: &str) -> Result<(), String> {
        let mut sessions = self
            .sessions
            .lock()
            .map_err(|_| "Lock error".to_string())?;
        sessions.remove(session_id);
        Ok(())
    }
}

fn uuid_v4() -> String {
    use std::time::{SystemTime, UNIX_EPOCH};
    let now = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_default();
    format!("pty-{}-{}", now.as_secs(), now.subsec_nanos())
}

use notify::{RecursiveMode, Watcher};
use notify_debouncer_mini::{new_debouncer, DebouncedEventKind};
use std::path::Path;
use std::sync::mpsc;
use std::time::Duration;

#[allow(dead_code)]
pub struct FileWatcher {
    _watcher: notify::RecommendedWatcher,
}

pub enum WatchEvent {
    CheckpointChanged,
    SessionChanged(#[allow(dead_code)] String),
    ConfigChanged,
}

/// Start watching a repo for Entire-related file changes
pub fn watch_repo(
    repo_path: &str,
    callback: impl Fn(WatchEvent) + Send + 'static,
) -> Result<(), String> {
    let git_dir = Path::new(repo_path).join(".git");
    let entire_dir = Path::new(repo_path).join(".entire");

    let (tx, rx) = mpsc::channel();

    let mut debouncer = new_debouncer(Duration::from_millis(500), tx)
        .map_err(|e| format!("Failed to create debouncer: {}", e))?;

    // Watch session directory
    let sessions_dir = git_dir.join("entire-sessions");
    if sessions_dir.exists() {
        debouncer
            .watcher()
            .watch(&sessions_dir, RecursiveMode::NonRecursive)
            .map_err(|e| format!("Failed to watch sessions: {}", e))?;
    }

    // Watch .entire/ config directory
    if entire_dir.exists() {
        debouncer
            .watcher()
            .watch(&entire_dir, RecursiveMode::NonRecursive)
            .map_err(|e| format!("Failed to watch .entire: {}", e))?;
    }

    // Watch git refs for checkpoint branch changes
    let refs_dir = git_dir.join("refs/heads/entire");
    if refs_dir.exists() {
        debouncer
            .watcher()
            .watch(&refs_dir, RecursiveMode::Recursive)
            .map_err(|e| format!("Failed to watch refs: {}", e))?;
    }

    // Spawn thread to process events
    std::thread::spawn(move || {
        let _debouncer = debouncer; // Keep alive
        for result in rx {
            match result {
                Ok(events) => {
                    for event in events {
                        if event.kind == DebouncedEventKind::Any {
                            let path_str = event.path.to_string_lossy();
                            if path_str.contains("entire-sessions") {
                                callback(WatchEvent::SessionChanged(
                                    event.path.to_string_lossy().to_string(),
                                ));
                            } else if path_str.contains("refs/heads/entire/checkpoints") {
                                callback(WatchEvent::CheckpointChanged);
                            } else if path_str.contains(".entire") {
                                callback(WatchEvent::ConfigChanged);
                            }
                        }
                    }
                }
                Err(e) => {
                    eprintln!("Watch error: {:?}", e);
                }
            }
        }
    });

    Ok(())
}
